{
  "id": "sci-ix-s01-cell-basics",
  "sessionNumber": 1,
  "title": "The Building Blocks of Life: Discovering the Cell and Its Organelles",
  "duration": 45,
  "learningOutcomes": [
    "Define a cell as the fundamental structural and functional unit of life.",
    "Differentiate between prokaryotic and eukaryotic cells based on nuclear presence.",
    "Identify key organelles (nucleus, mitochondria, chloroplasts, ribosomes) and describe their specific functions.",
    "Compare plant and animal cell structures to highlight unique features like the cell wall."
  ],
  "introduction": "Hook: Display a high-resolution image of a bustling city alongside an onion skin under a microscope. Ask students: 'If this entire city is one single living organism, what are its workers? What do they build?' Inquiry Question: 'Why can't we see cells with the naked eye, and how does their tiny structure allow them to perform complex tasks like breathing or growing?'",
  "theory": {
    "overview": "The cell theory states that all living things are made of cells. Cells vary in size but share common components called organelles, each performing specific jobs similar to organs in a body.",
    "keyPoints": [
      "Cells are the smallest unit capable of independent life functions.",
      "Prokaryotes lack a nucleus; Eukaryotes have a membrane-bound nucleus.",
      "Mitochondria generate energy (ATP), while chloroplasts conduct photosynthesis in plants.",
      "The cell wall provides rigidity and support, found only in plant cells."
    ],
    "detailedContent": "We begin with the Cell Theory: proposed by Schleiden and Schwann. All living organisms are composed of one or more cells. The nucleus acts as the control center containing DNA (the blueprint). Mitochondria are known as the 'powerhouses' because they convert glucose into ATP through cellular respiration. Ribosomes synthesize proteins based on instructions from the nucleus. In plant cells, chloroplasts contain chlorophyll to trap sunlight for photosynthesis. The cell membrane regulates what enters and exits the cell (selective permeability), while the rigid cell wall in plants prevents bursting under osmotic pressure."
  },
  "activities": [
    {
      "name": "Organelle Match-Up Challenge",
      "instructions": [
        "Distribute cards with organelle names on one set and functions/descriptions on another.",
        "Students must physically move to the front of the class or pair up to match the correct function to the organelle (e.g., 'Powerhouse' matches 'Mitochondria').",
        "Discuss why plant cells have a cell wall but animal cells do not, using visual aids."
      ],
      "durationMinutes": 10
    }
  ],
  "materials": {
    "ppt": {
      "title": "Introduction to Cell Biology: Structure and Function",
      "slides": [
        {
          "slideTitle": "What is a Cell?",
          "bulletPoints": [
            "Definition of the cell as the basic unit of life.",
            "History: Robert Hooke (1665) coined the term 'cell'.",
            "Cell Theory basics."
          ]
        },
        {
          "slideTitle": "Prokaryotes vs. Eukaryotes",
          "bulletPoints": [
            "Visual comparison of bacteria (prokaryote) and human cells (eukaryote).",
            "Key difference: Presence or absence of a true nucleus.",
            "Size differences."
          ]
        },
        {
          "slideTitle": "The Animal Cell",
          "bulletPoints": [
            "Diagram labeling: Nucleus, Cytoplasm, Mitochondria, Ribosomes, Cell Membrane.",
            "Function of each labeled part.",
            "Absence of cell wall and chloroplasts."
          ]
        },
        {
          "slideTitle": "The Plant Cell",
          "bulletPoints": [
            "Diagram labeling: Nucleus, Cytoplasm, Mitochondria, Ribosomes, Chloroplasts, Vacuole.",
            "Unique features: Rigid cell wall and large central vacuole.",
            "Role of chlorophyll."
          ]
        }
      ]
    },
    "pdf": {
      "documentTitle": "Student Study Guide: Cell Organelles Cheat Sheet",
      "keyInformation": [
        "Summary table comparing Plant vs. Animal cells.",
        "Mnemonics for remembering organelle functions (e.g., 'Mitochondria = Powerhouse').",
        "Glossary of terms: Cytoplasm, Nucleus, Membrane-bound."
      ]
    },
    "docx": {
      "outlineTitle": "Lesson Plan Outline: Session 1 - Cell Basics",
      "sections": [
        "Introduction (5 mins): Hook and Inquiry.",
        "Direct Instruction (20 mins): Theory delivery with PPT visuals.",
        "Activity (10 mins): Organelle Match-Up.",
        "Assessment & Wrap-up (10 mins): Quiz and Q&A."
      ]
    }
  },
  "homework": {
    "task": "Interactive or practical homework task",
    "estimatedTimeMinutes": 30
  },
  "assessment": {
    "questions": [
      "1. Who is credited with coining the term 'cell' after observing cork under a microscope?",
      "2. Which organelle is known as the 'powerhouse of the cell' and why?",
      "3. Name one structural feature found in plant cells but absent in animal cells.",
      "4. What is the primary function of ribosomes?"
    ],
    "answerKey": [
      "1. Robert Hooke",
      "2. Mitochondria; because it generates energy (ATP) through cellular respiration.",
      "3. Cell wall, Chloroplasts, or Large Central Vacuole.",
      "4. Protein synthesis."
    ]
  },
  "assignment": {
    "taskDescription": "Draw a labeled diagram of both an animal and a plant cell on separate sheets. Clearly label at least five organelles in each and write one sentence describing the function of two unique features (e.g., Cell Wall, Chloroplasts).",
    "rubric": [
      "Accuracy of labels (5 points)",
      "Correct identification of 5+ organelles per cell type (10 points)",
      "Clarity and neatness of diagrams (3 points)",
      "Explanation of unique features showing understanding (2 points)"
    ],
    "answerKey": "Student must produce two distinct drawings. Animal cell should show Nucleus, Mitochondria, Ribosomes, Cell Membrane, Cytoplasm. Plant cell must include all above plus Chloroplasts and a thick Cell Wall surrounding the membrane."
  }
}
